from math import gcd

def add_fractions(a, b, c, d):
    num = a * d + c * b
    den = b * d

    if num == 0:
        return (0, 1)

    g = gcd(num, den)
    num //= g
    den //= g

    if den < 0:
        num = -num
        den = -den

    return (num, den)
