def days_between(y1, m1, d1, y2, m2, d2) -> int:
    def is_leap(y):
        return y % 4 == 0 and (y % 100 != 0 or y % 400 == 0)

    def ordinal(y, m, d):
        days_before_month_common = [0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334]
        days = 365 * (y - 1) + (y - 1) // 4 - (y - 1) // 100 + (y - 1) // 400
        days += days_before_month_common[m - 1]
        if m > 2 and is_leap(y):
            days += 1
        return days + d - 1

    return abs(ordinal(y2, m2, d2) - ordinal(y1, m1, d1))
