        raise ValueError("base must be between 2 and 36")

    if n == 0:
        return "0"

    digits = "0123456789abcdefghijklmnopqrstuvwxyz"
    sign = "-" if n < 0 else ""
    n = abs(n)

    result = []
    while n:
        n, remainder = divmod(n, b)
        result.append(digits[remainder])

    return sign + "".join(reversed(result))
