import math

def add_fractions(a, b, c, d):
    if b == 0 or d == 0:
        raise ValueError("Denominators cannot be zero")

    numerator = a * d + c * b
    denominator = b * d

    if numerator == 0:
        return (0, 1)

    gcd_val = math.gcd(numerator, denominator)
    numerator //= gcd_val
    denominator //= gcd_val

    if denominator < 0:
        numerator = -numerator
        denominator = -denominator

    return (numerator, denominator)
