        return False

    roman_to_int = {
        'I': 1, 'V': 5, 'X': 10, 'L': 50,
        'C': 100, 'D': 500, 'M': 1000
    }

    # Check for invalid characters
    for char in s:
        if char not in roman_to_int:
            return False

    # Check for more than three consecutive identical characters
    for char in 'IVXLCDM':
        if char * 4 in s:
            return False

    # Check for invalid subtractive pairs
    invalid_pairs = ['IL', 'IC', 'ID', 'IM', 'XD', 'XM', 'LM', 'VV', 'LL', 'DD']
    for pair in invalid_pairs:
        if pair in s:
            return False

    # Check the standard form
    prev_value = 0
    total = 0
    for char in reversed(s):
        value = roman_to_int[char]
        if value < prev_value:
            total -= value
        else:
            total += value
            prev_value = value

    # Check if the total is within the valid range
